Bash(node -e "
const fs = require\(''fs''\);
const path = require\(''path''\);
const os = require\(''os''\);
const crypto = require\(''crypto''\);

// 读取 token
const cacheDir = path.join\(os.homedir\(\), ''.aws'', ''sso'', ''cache''\);
const files = fs.readdirSync\(cacheDir\).filter\(f => f.endsWith\(''.json''\)\);
let token = null;

for \(const file of files\) {
  const data = JSON.parse\(fs.readFileSync\(path.join\(cacheDir, file\), ''utf-8''\)\);
  if \(data.accessToken && data.refreshToken\) {
    token = data;
    break;
  }
}

if \(!token\) {
  console.log\(''No token found''\);
  process.exit\(1\);
}

console.log\(''Token found, expires:'', token.expiresAt\);

// 构建简单请求（无工具）
const machineId = crypto.createHash\(''sha256''\).update\(''test-lite''\).digest\(''hex''\).substring\(0, 32\);

const headers = {
  ''content-type'': ''application/json'',
  ''x-amzn-codewhisperer-optout'': ''true'',
  ''x-amzn-kiro-agent-mode'': ''vibe'',
  ''x-amz-user-agent'': ''aws-sdk-js/1.0.0 KiroIDE-1.7.1-'' + machineId,
  ''user-agent'': ''aws-sdk-js/1.0.0 ua/2.1 os/windows lang/js api/codewhispererruntime#1.0.0 m/E KiroIDE-1.7.1-'' + machineId,
  ''amz-sdk-invocation-id'': crypto.randomUUID\(\),
  ''amz-sdk-request'': ''attempt=1; max=1'',
  ''Authorization'': ''Bearer '' + token.accessToken,
  ''Connection'': ''close'',
};

const body = {
  conversationState: {
    agentContinuationId: crypto.randomUUID\(\),
    agentTaskType: ''vibe'',
    chatTriggerType: ''MANUAL'',
    conversationId: crypto.randomUUID\(\),
    currentMessage: {
      userInputMessage: {
        content: ''你好'',
        modelId: ''claude-sonnet-4'',
        origin: ''AI_EDITOR'',
      }
    },
    history: [],
  }
};

console.log\(''Request body:'', JSON.stringify\(body, null, 2\)\);

fetch\(''https://q.us-east-1.amazonaws.com/generateAssistantResponse'', {
  method: ''POST'',
  headers,
  body: JSON.stringify\(body\),
}\).then\(async res => {
  console.log\(''Status:'', res.status\);
  if \(!res.ok\) {
    const text = await res.text\(\);
    console.log\(''Error:'', text\);
  } else {
    const buffer = await res.arrayBuffer\(\);
    console.log\(''Response size:'', buffer.byteLength, ''bytes''\);
  }
}\).catch\(err => {
  console.log\(''Fetch error:'', err.message\);
}\);
")
